                    boss_id: bossId,
                    name: name,
                    title: title,
                    company: company,
                    location: '',
                    salary_expect: '',
                    work_years: '',
                    education_level: '',
                    profile_url: link ? link.href : ''
                });
            } catch (e) {
                continue;
            }
        }
    }

    return candidates;
}
